<?php if ( ! defined( 'ABSPATH' ) ) exit; global $wpdb; ?>
<div class="wrap qm2026"><h1><?php esc_html_e('Equipos',QM2026_TEXT_DOMAIN); ?></h1><table class="widefat striped"><thead><tr><th><?php esc_html_e('Código',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Nombre',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Grupo',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Placeholder',QM2026_TEXT_DOMAIN); ?></th></tr></thead><tbody><?php foreach($wpdb->get_results('SELECT * FROM '.qm2026_table('teams').' ORDER BY group_code,name') as $t): ?><tr><td><?php echo esc_html($t->team_code); ?></td><td><?php echo esc_html($t->name); ?></td><td><?php echo esc_html($t->group_code); ?></td><td><?php echo $t->placeholder?esc_html__('Sí',QM2026_TEXT_DOMAIN):esc_html__('No',QM2026_TEXT_DOMAIN); ?></td></tr><?php endforeach; ?></tbody></table></div>
